data.content:
**MSTest doesn't have `Assert.IsGreaterThan` or `Assert.IsInRange`** — those don't exist. Here's what MSTest actually provides for comparisons:

| Need | MSTest Approach |
|---|---|
| Greater/less than | `Assert.IsTrue(val > x)` |
| Range check | `Assert.IsTrue(val >= lo && val <= hi)` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

Here's a complete test class using the real MSTest API:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        double result = _calc.CalculatePercentage(3, 4);
        Assert.AreEqual(75.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsAlwaysInRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Percentage {result} is outside [0, 100]");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsExpectedGrade(
        double percentage, string expectedGrade)
    {
        Assert.AreEqual(expectedGrade, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_RawEqualsMax_Returns100()
    {
        Assert.AreEqual(100.0, _calc.NormalizeScore(50, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_RawExceedsMax_CapsAt100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, 0.001);
        // Verify it doesn't go over
        Assert.IsTrue(result <= 100.0, "Score must not exceed 100");
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_Returns0()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 100), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

Key patterns used:

- **`Assert.AreEqual(expected, actual, delta)`** — the `delta` (3rd arg) handles floating-point precision; without it, `75.0 == 75.0000000001` would fail
- **`Assert.IsTrue(condition, message)`** — your substitute for range/comparison assertions; always include a message so failures are readable
- **`Assert.ThrowsException<T>`** — validates boundary guard clauses
- **`[DataTestMethod]` + `[DataRow]`** — tests every grade boundary in one method
